#include <stdio.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    for(int i=0;i<T;++i){
        double a,b,c;
        if(scanf("%lf %lf %lf",&a,&b,&c)!=3) return 0;
        printf("Total Marks = %.1f", a+b+c);
        if(i<T-1) printf("\\n");
    }
    return 0;
}

