code.Java:
import java.io.*;
import java.util.*;
import java.util.Locale;
public class Main{
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder allInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            allInput.append(line).append('\n');
        }
        String data = allInput.toString().replace("\\n", " ").replace("\r", " ").trim();
        if (data.isEmpty()) return;
        String[] parts = data.split("\\s+");
        int idx = 0;
        int T = Integer.parseInt(parts[idx++]);
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            double a = Double.parseDouble(parts[idx++]);
            double b = Double.parseDouble(parts[idx++]);
            double c = Double.parseDouble(parts[idx++]);
            sb.append(String.format(Locale.US, "Total Marks = %.1f", a + b + c));
            if (i < T - 1) sb.append("\\n");
        }
        System.out.print(sb.toString());
    }
}

